head.script:
//전역변수
scwin.memJson = $c.data.getMemInfo(); // 로그인 정보를 가져온다.
scwin.privAdmin = scwin.memJson.privAdmin; // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님

scwin.g_sCurrData = $c.date.getServerDateTime("yyyyMMdd");
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 소속 자회사
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd; // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd; // 사용자소속구분코드
scwin.isSubCompany = false;
scwin.txtCoClsCd = "";
scwin.isStart = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	cbx_printCheck.setValue(1);
};

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    ica_spplyStDt.setValue(scwin.g_sCurrData.substring(0,6) + "01");
    ica_spplyEndDt.setValue(scwin.g_sCurrData);
    ica_spplyStDt.focus();
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를 '동부 EXPRESS'로 Default set
    if (scwin.vUserHomeClsCd !== ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    scwin.isStart = true;
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 조회 조건 검증
//-------------------------------------------------------------------------
scwin.f_Validation = async function() {
    let ret = await $c.gus.cfValidate([ica_spplyStDt, ica_spplyEndDt]); 
    if (!ret) { 
        return false; 
    }

    if ($c.gus.cfIsNull(ica_spplyStDt.getValue()) && !$c.gus.cfIsNull(ica_spplyEndDt.getValue())) {
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_003, ["일자"]));
        ica_spplyStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_spplyStDt.getValue()) && $c.gus.cfIsNull(ica_spplyEndDt.getValue())) {
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_003, ["일자"]));
        ica_spplyEndDt.focus();
        return false;
    }

    return true;
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) { 
    await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc, ed_coCd.getValue(), ed_coNm.getValue(), 
                                                pWinCloseTF, null, null, null, null, null, null, null, null, null); 
};

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) { 
    // SET
    if (rtnList != null) { if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]); // 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        if (!ed_coCd.options) ed_coCd.options = {};
        ed_coCd.options.hidVal = rtnList[0]; // 히든값
        scwin.txtCoClsCd = rtnList[1]; // 회사구분    
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        if (!ed_coCd.options) ed_coCd.options = {};
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) { // 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if(scwin.isStart == true) {
        if (scwin.privAdmin === 'T' || !scwin.isSubCompany) {   // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }

    scwin.isStart = false;
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() { 
    $c.gus.cfInitObjects([ica_spplyStDt, ica_spplyEndDt]); 
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    if (ed_coCd.getValue() == "") {
        await $c.win.alert("회사코드는 필수 입력 조회 조건입니다.");
        return;
    }
    if ($c.gus.cfIsNull(ica_spplyStDt.getValue()) && !$c.gus.cfIsNull(ica_spplyEndDt.getValue())) {
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_003, ["일자"]));
        ica_spplyStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_spplyStDt.getValue()) && $c.gus.cfIsNull(ica_spplyEndDt.getValue())) {
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_003, ["일자"]));
        ica_spplyEndDt.focus();
        return false;
    }

    dma_search.set("coClsCd", scwin.txtCoClsCd);

    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 오즈 검색 후 결과를 화면 하단에 표시
//-------------------------------------------------------------------------
scwin.f_OzReport = async function() {

    let ret = await $c.gus.cfValidate([ed_coCd, ica_spplyStDt, ica_spplyEndDt]);
    if (!ret)
        return false;

    let data = {
        odiName: "fi_401_01_100",
        reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_100.ozr",
        odiParam : {
            spplyDtSt : ica_spplyStDt.getValue(),
            spplyDtEnd : ica_spplyEndDt.getValue(),
            coCd : ed_coCd.getValue(),
            coClsCd : scwin.txtCoClsCd
        },
        viewerParam : {
            viewer: 100,
            useprogressbar : false,
        },
        formParam: {}
    };

    if(cbx_printCheck.getValue() == "1" && cbx_previewCheck.getValue() == "0"){
        let opts = {
            type:'print', // viewer, print, download
            printMode:'view', // silent, view
        }
        $c.ext.printOzReport(data, opts);
    }else if((cbx_printCheck.getValue() == "0" && cbx_previewCheck.getValue() == "1") || (cbx_printCheck.getValue() == "1" && cbx_previewCheck.getValue() == "1")) {
        let opts = {
            type:'viewer', // viewer, print, download
            printMode:'view', // silent, view
        };
        $c.ext.openOzReport(data, opts);
    } else {
        let opts = {
            filename: 'fi_401_01_100',
            exportMode:'view'
        }
        $c.ext.downloadOzReport(data, opts);
    }
};

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function() { 
    if (ds_evid.getRowCount() == 0) return;
    let gridColCount = 0;
    for(let i = 0; i < gr_evid.getTotalCol(); i++) {
        if(gr_evid.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let infoArr = [{
        rowIndex : 0,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "부가세월계표",
        textAlign : "center",     //정렬
        fontSize : 12,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 2,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "부가세월계표년월 ["+$c.gus.cfGetFormatStr(ica_spplyStDt.getValue(), "####/##/##")+ " ~ " + $c.gus.cfGetFormatStr(ica_spplyEndDt.getValue(), "####/##/##")+"]",
        textAlign : "left",     //정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    }];

    const options = {
        fileName: "부가세월계표" + ".xlsx",
        sheetName: "부가세월계표",
        startRowIndex : 3,        
        startColumnIndex : 0,
        type : 1,
    };

    await $c.data.downloadGridViewExcel(gr_evid, options,infoArr);
};

scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};


scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.udc_dongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("");
    if (ed_coCd.getValue() != ""){
        scwin.f_PopUpCompanyInfo('T');
    }
    else{
        ed_coNm.setValue("");
    }
};

scwin.sbm_search_submitdone = async function (e) {

    let rowCnt = ds_evid.getRowCount();

    if( rowCnt == 0 ){
		await $c.win.alert(MSG_CM_WRN_002);
	} 

    totalRows.setValue(rowCnt);
};

scwin.udc_dongbuGroupCompanyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.btn_ozprint_onclick = function (e) {
    scwin.f_OzReport();
};
